# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.request
import urllib.error
from base64 import b64encode

def lambda_handler(event, context):
    request = event['Records'][0]['cf']['request']
    headers = request['headers']
    
    enrich_data = {}
    
    if 'x-enrich-url' in headers:
        enrich_urls = headers['x-enrich-url']
        
        for idx, url_header in enumerate(enrich_urls):
            url = url_header['value']
            
            try:
                req = urllib.request.Request(url, method='GET')
                req.add_header('User-Agent', 'Lambda-Edge-Enrichment/1.0')
                
                with urllib.request.urlopen(req, timeout=2) as response:
                    if response.status == 200:
                        content_type = response.headers.get('Content-Type', '')
                        data = response.read()
                        
                        if 'application/json' in content_type:
                            enrich_data[f'url_{idx}'] = json.loads(data.decode('utf-8'))
                        else:
                            enrich_data[f'url_{idx}'] = data.decode('utf-8')
            except urllib.error.HTTPError as e:
                enrich_data[f'url_{idx}_error'] = f'HTTP {e.code}'
            except urllib.error.URLError as e:
                enrich_data[f'url_{idx}_error'] = f'URL Error: {str(e.reason)}'
            except Exception as e:
                enrich_data[f'url_{idx}_error'] = str(e)
    
    if enrich_data:
        enriched_json = json.dumps(enrich_data)
        enriched_b64 = b64encode(enriched_json.encode('utf-8')).decode('utf-8')
        
        headers['x-enriched-data'] = [{
            'key': 'X-Enriched-Data',
            'value': enriched_b64
        }]
    
    return request